import java.util.*;

public class ScratchPad {

    public static List<Character> getValidOrder(HashMap<Character, List<Character>> dependency) {
        Map<Character, Integer> inOrderMap = new HashMap<>();
        Map<Character, List<Character>> graph = new HashMap<>();

        // Initialize inOrder for each block and build the graph
        for (char p : dependency.keySet()) {
            inOrderMap.put(p, dependency.get(p).size());

            for (char q : dependency.get(p)) {
                if (!graph.containsKey(q)) {
                    graph.put(q, new ArrayList<Character>());
                }
                graph.get(q).add(p);
            }
        }

        // Finding all nodes with no incoming edges
        List<Character> result = new ArrayList<>();
        Queue<Character> queue = new LinkedList<>();
        for (char c : inOrderMap.keySet()) {
            if (inOrderMap.get(c) == 0) {
                queue.offer(c);
            }
        }

        // Kahn's Algorithm for Topological Sorting
        while (!queue.isEmpty()) {
            char ch = queue.poll();
            result.add(ch);

            if (graph.containsKey(ch)) {
                for (char neighbor : graph.get(ch)) {
                    inOrderMap.put(neighbor, inOrderMap.get(neighbor) - 1);
                    if (inOrderMap.get(neighbor) == 0) {
                        queue.offer(neighbor);
                    }
                }
            }
        }

        // Check if there's a cycle
        if (result.size() != dependency.size()) {
            throw new RuntimeException("Cycle detected, invalid input");
        }

        return result;
    }

    public static void main(String[] args) {
        HashMap<Character, List<Character>> dependency = new HashMap<>();

        dependency.put('M', Arrays.asList());
        dependency.put('N', Arrays.asList('M'));
        dependency.put('O', Arrays.asList('M'));
        dependency.put('P', Arrays.asList('N', 'O'));

        try {
            List<Character> order = getValidOrder(dependency);
            System.out.println("Valid Assembly Order: " + order);
        } catch (RuntimeException e) {
            System.out.println(e.getMessage());
        }
    }
}
